import React, { useState } from 'react';
import '../styles/NotesRequestPage.css';

export default function NotesRequestPage() {
  const [requests, setRequests] = useState([
    { id: 1, from: 'Alice Johnson', notesTitle: 'Advanced JavaScript', date: '2025-02-12', status: 'pending' },
    { id: 2, from: 'Bob Smith', notesTitle: 'Web Design Principles', date: '2025-02-11', status: 'pending' },
    { id: 3, from: 'Charlie Brown', notesTitle: 'React Performance', date: '2025-02-10', status: 'accepted' },
    { id: 4, from: 'Diana Prince', notesTitle: 'TypeScript Guide', date: '2025-02-09', status: 'rejected' },
  ]);

  const [filter, setFilter] = useState('all');

  const filteredRequests = requests.filter((request) => {
    if (filter === 'all') return true;
    return request.status === filter;
  });

  const handleAccept = (id) => {
    setRequests(
      requests.map((req) =>
        req.id === id ? { ...req, status: 'accepted' } : req
      )
    );
  };

  const handleReject = (id) => {
    setRequests(
      requests.map((req) =>
        req.id === id ? { ...req, status: 'rejected' } : req
      )
    );
  };

  const getStatusBadge = (status) => {
    return (
      <span className={`status-badge ${status}`}>
        {status.charAt(0).toUpperCase() + status.slice(1)}
      </span>
    );
  };

  return (
    <div className="requests-container">
      <div className="requests-header">
        <h1>Notes Requests</h1>
        <p>Manage requests to share notes with peers</p>
      </div>

      <div className="requests-filter">
        <button
          className={`filter-btn ${filter === 'all' ? 'active' : ''}`}
          onClick={() => setFilter('all')}
        >
          All ({requests.length})
        </button>
        <button
          className={`filter-btn ${filter === 'pending' ? 'active' : ''}`}
          onClick={() => setFilter('pending')}
        >
          Pending ({requests.filter((r) => r.status === 'pending').length})
        </button>
        <button
          className={`filter-btn ${filter === 'accepted' ? 'active' : ''}`}
          onClick={() => setFilter('accepted')}
        >
          Accepted ({requests.filter((r) => r.status === 'accepted').length})
        </button>
      </div>

      <div className="requests-list">
        {filteredRequests.length === 0 ? (
          <div className="no-requests">
            <p>No requests to display</p>
          </div>
        ) : (
          filteredRequests.map((request) => (
            <div key={request.id} className="request-card">
              <div className="request-content">
                <h3>{request.from}</h3>
                <p className="request-notes">
                  Requested: <strong>{request.notesTitle}</strong>
                </p>
                <div className="request-meta">
                  <span className="request-date">{request.date}</span>
                  {getStatusBadge(request.status)}
                </div>
              </div>
              <div className="request-actions">
                {request.status === 'pending' && (
                  <>
                    <button
                      className="btn-accept"
                      onClick={() => handleAccept(request.id)}
                    >
                      Accept
                    </button>
                    <button
                      className="btn-reject"
                      onClick={() => handleReject(request.id)}
                    >
                      Reject
                    </button>
                  </>
                )}
                {request.status === 'accepted' && (
                  <span className="action-message">✓ Accepted</span>
                )}
                {request.status === 'rejected' && (
                  <span className="action-message">✗ Rejected</span>
                )}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
